import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import DropZone from '../components/DropZone';
import ProgressBar from '../components/ProgressBar';
import ParsePreview from '../components/ParsePreview';
import Toast from '../components/Toast';
import api from '../api/axios';

function UploadPage() {
  const navigate = useNavigate();
  const [isUploading, setIsUploading] = useState(false);
  const [parsedData, setParsedData] = useState(null);
  const [error, setError] = useState(null);
  const [toast, setToast] = useState(null);

  const handleFileSelect = async (file) => {
    // 파일 크기 검증
    if (file.size > 10 * 1024 * 1024) {
      setError('파일 크기가 10MB를 초과합니다.');
      return;
    }

    // 파일 형식 검증
    const allowedTypes = ['image/jpeg', 'image/png', 'application/pdf'];
    if (!allowedTypes.includes(file.type)) {
      setError('JPG, PNG, PDF 파일만 업로드 가능합니다.');
      return;
    }

    setError(null);
    setIsUploading(true);

    const formData = new FormData();
    formData.append('file', file);

    try {
      const response = await api.post('/api/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      setParsedData(response.data);
    } catch (err) {
      setError(err.response?.data?.detail || 'OCR 파싱에 실패했습니다.');
    } finally {
      setIsUploading(false);
    }
  };

  const handleSave = (data) => {
    // localStorage에 저장 (Vercel 서버리스 데이터 손실 대응)
    const expenses = JSON.parse(localStorage.getItem('expenses') || '[]');
    expenses.push(data);
    localStorage.setItem('expenses', JSON.stringify(expenses));

    setToast({ type: 'success', message: '저장되었습니다!' });
    setTimeout(() => navigate('/'), 1000);
  };

  const handleCancel = () => {
    setParsedData(null);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <Header />

      <main className="max-w-4xl mx-auto px-4 py-6">
        <h1 className="text-2xl font-bold mb-6">영수증 업로드</h1>

        <DropZone onFileSelect={handleFileSelect} />

        {isUploading && (
          <div className="mt-6">
            <ProgressBar progress={50} message="OCR 분석 중..." />
          </div>
        )}

        {error && (
          <div className="mt-6 bg-red-50 border border-red-200 text-red-700 rounded-lg p-4">
            <p>{error}</p>
            <button
              onClick={() => setError(null)}
              className="mt-2 text-sm underline hover:no-underline"
            >
              다시 시도
            </button>
          </div>
        )}

        {parsedData && !isUploading && (
          <div className="mt-6">
            <ParsePreview
              data={parsedData}
              onSave={handleSave}
              onCancel={handleCancel}
            />
          </div>
        )}
      </main>

      {toast && (
        <Toast
          type={toast.type}
          message={toast.message}
          onClose={() => setToast(null)}
        />
      )}
    </div>
  );
}

export default UploadPage;
```

