import { useState, useEffect } from 'react';
import Header from '../components/Header';
import SummaryCard from '../components/SummaryCard';
import FilterBar from '../components/FilterBar';
import ExpenseCard from '../components/ExpenseCard';
import api from '../api/axios';

function Dashboard() {
  const [expenses, setExpenses] = useState([]);
  const [summary, setSummary] = useState(null);
  const [filter, setFilter] = useState(null);

  useEffect(() => {
    fetchExpenses();
    fetchSummary();
  }, [filter]);

  const fetchExpenses = async () => {
    try {
      // localStorage에서도 데이터 로드 (Vercel 서버리스 대응)
      const localExpenses = JSON.parse(localStorage.getItem('expenses') || '[]');

      const params = filter ? { from: filter.from, to: filter.to } : {};
      const response = await api.get('/api/expenses', { params });

      // 서버 + localStorage 데이터 병합 (중복 제거)
      const combined = [...response.data, ...localExpenses];
      const unique = combined.filter(
        (v, i, a) => a.findIndex(t => t.id === v.id) === i
      );

      setExpenses(unique);
    } catch (err) {
      // 서버 요청 실패 시 localStorage만 사용
      const localExpenses = JSON.parse(localStorage.getItem('expenses') || '[]');
      setExpenses(localExpenses);
    }
  };

  const fetchSummary = async () => {
    try {
      const response = await api.get('/api/summary');
      setSummary(response.data);
    } catch (err) {
      console.error('통계 조회 실패:', err);
    }
  };

  const handleFilter = (filterData) => {
    setFilter(filterData);
  };

  const handleReset = () => {
    setFilter(null);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <Header />

      <main className="max-w-4xl mx-auto px-4 py-6">
        {/* 합계 통계 */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
          <SummaryCard title="총 지출" amount={summary?.total_amount || 0} />
          <SummaryCard title="이번 달 지출" amount={summary?.this_month_amount || 0} />
        </div>

        {/* 날짜 필터 */}
        <FilterBar onFilter={handleFilter} onReset={handleReset} />

        {/* 지출 내역 */}
        <div className="mt-6">
          <h2 className="text-lg font-semibold mb-4">지출 내역 ({expenses.length}건)</h2>

          {expenses.length === 0 ? (
            <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-12 text-center">
              <div className="text-gray-400 mb-4">
                <svg className="mx-auto h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <p className="text-gray-600 mb-2">아직 등록된 지출 내역이 없습니다</p>
              <p className="text-sm text-gray-500 mb-4">영수증을 업로드해 보세요</p>
              <a
                href="/upload"
                className="inline-block bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-2 px-4 rounded-lg transition-colors"
              >
                + 첫 영수증 등록하기
              </a>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {expenses.map((expense) => (
                <ExpenseCard key={expense.id} expense={expense} />
              ))}
