import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import EditForm from '../components/EditForm';
import Modal from '../components/Modal';
import Toast from '../components/Toast';
import api from '../api/axios';

function ExpenseDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [expense, setExpense] = useState(null);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [toast, setToast] = useState(null);

  useEffect(() => {
    fetchExpense();
  }, [id]);

  const fetchExpense = async () => {
    try {
      const response = await api.get('/api/expenses');
      const found = response.data.find(e => e.id === id);

      if (!found) {
        // localStorage에서 찾기
        const localExpenses = JSON.parse(localStorage.getItem('expenses') || '[]');
        const localFound = localExpenses.find(e => e.id === id);
        setExpense(localFound);
      } else {
        setExpense(found);
      }
    } catch (err) {
      console.error('항목 조회 실패:', err);
    }
  };

  const handleSave = async (updatedData) => {
    try {
      await api.put(`/api/expenses/${id}`, updatedData);

      // localStorage 업데이트
      const localExpenses = JSON.parse(localStorage.getItem('expenses') || '[]');
      const index = localExpenses.findIndex(e => e.id === id);
      if (index !== -1) {
        localExpenses[index] = updatedData;
        localStorage.setItem('expenses', JSON.stringify(localExpenses));
      }

      setToast({ type: 'success', message: '수정되었습니다!' });
      setExpense(updatedData);
    } catch (err) {
      setToast({ type: 'error', message: '수정에 실패했습니다.' });
    }
  };

  const handleDelete = async () => {
    try {
      await api.delete(`/api/expenses/${id}`);

      // localStorage에서도 삭제
      const localExpenses = JSON.parse(localStorage.getItem('expenses') || '[]');
      const filtered = localExpenses.filter(e => e.id !== id);
      localStorage.setItem('expenses', JSON.stringify(filtered));

      setToast({ type: 'success', message: '삭제되었습니다!' });
      setTimeout(() => navigate('/'), 1000);
    } catch (err) {
      setToast({ type: 'error', message: '삭제에 실패했습니다.' });
    }
  };

  if (!expense) {
    return (
      <div className="min-h-screen bg-gray-50">
        <Header />
        <main className="max-w-4xl mx-auto px-4 py-6">
          <p className="text-gray-600">항목을 찾을 수 없습니다.</p>
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Header />

      <main className="max-w-4xl mx-auto px-4 py-6">
        <button
          onClick={() => navigate('/')}
          className="text-indigo-600 hover:text-indigo-700 font-medium mb-4 flex items-center gap-1"
        >
          <span>←</span> 뒤로
        </button>

        <h1 className="text-2xl font-bold mb-6">지출 상세</h1>

        {expense.raw_image_path && (
          <div className="mb-6">
            <img
              src={`${import.meta.env.VITE_API_BASE_URL || 'http://localhost:8000'}/${expense.raw_image_path}`}
              alt="영수증 원본"
              className="max-h-[300px] mx-auto rounded-lg shadow-md"
            />
          </div>
        )}

        <EditForm
          expense={expense}
          onSave={handleSave}
          onDelete={() => setIsDeleteModalOpen(true)}
        />
      </main>

      <Modal
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDelete}
        title="지출 삭제"
        message="정말 삭제하시겠습니까? 이 작업은 되돌릴 수 없습니다."
      />

      {toast && (
        <Toast
          type={toast.type}
          message={toast.message}
          onClose={() => setToast(null)}
        />
      )}
    </div>
  );
}

export default ExpenseDetail;
